css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f8fafc; color: #1e293b; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 48px; height: 68px; background: white; box-shadow: 0 1px 8px rgba(0,0,0,0.06); position: sticky; top: 0; z-index: 100; }
.logo { font-size: 20px; font-weight: 800; color: #ea580c; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; }
.nav-right { display: flex; gap: 10px; }
.login { padding: 10px 18px; border-radius: 10px; border: 1px solid #e2e8f0; background: transparent; color: #1e293b; font-weight: 600; cursor: pointer; }
.list-prop { padding: 10px 18px; border-radius: 10px; border: none; background: #ea580c; color: white; font-weight: 700; cursor: pointer; }
.hero { min-height: 580px; background: linear-gradient(135deg, #1e3a5f 0%, #0f172a 100%); display: flex; align-items: center; justify-content: center; position: relative; overflow: hidden; }
.hero-overlay { position: absolute; inset: 0; background: url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><circle cx="50" cy="50" r="40" fill="none" stroke="rgba(234,88,12,0.1)" stroke-width="0.5"/></svg>') center/cover; opacity: 0.5; }
.hero-content { position: relative; z-index: 1; text-align: center; width: 100%; max-width: 860px; padding: 0 24px; color: white; }
h1 { font-size: 64px; font-weight: 900; line-height: 1; letter-spacing: -2px; margin-bottom: 14px; } h1 span { color: #fb923c; }
.hero-content > p { color: rgba(255,255,255,0.7); font-size: 17px; margin-bottom: 28px; }
.search-panel { background: white; border-radius: 20px; overflow: hidden; margin-bottom: 16px; box-shadow: 0 20px 60px rgba(0,0,0,0.3); }
.sp-tabs { display: flex; border-bottom: 1px solid #f1f5f9; }
.sp-tab { flex: 1; height: 48px; border: none; background: transparent; font-size: 15px; font-weight: 600; color: #6b7280; cursor: pointer; transition: all 0.2s; } .sp-tab.active { color: #ea580c; border-bottom: 2px solid #ea580c; }
.sp-form { display: flex; padding: 16px; gap: 12px; align-items: flex-end; }
.sp-field { flex: 1; } .sp-field label { display: block; font-size: 11px; font-weight: 700; color: #9ca3af; letter-spacing: 1px; margin-bottom: 6px; }
.sp-field input, .sp-field select { width: 100%; height: 44px; border-radius: 10px; border: 1px solid #e2e8f0; padding: 0 14px; font-size: 14px; color: #1e293b; outline: none; background: #f8fafc; } input:focus, select:focus { border-color: #ea580c; background: white; }
.sp-search { height: 44px; padding: 0 28px; border-radius: 10px; border: none; background: #ea580c; color: white; font-weight: 800; font-size: 15px; cursor: pointer; white-space: nowrap; }
.quick-links { display: flex; align-items: center; gap: 10px; } .quick-links span { color: rgba(255,255,255,0.5); font-size: 13px; } .quick-links a { color: rgba(255,255,255,0.8); text-decoration: none; font-size: 13px; font-weight: 600; background: rgba(255,255,255,0.1); padding: 5px 12px; border-radius: 20px; }
.listings { padding: 48px; }
.listings-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 24px; } .listings-header h2 { font-size: 28px; font-weight: 800; }
.see-all { color: #ea580c; text-decoration: none; font-weight: 600; font-size: 15px; }
.listings-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 20px; }
.listing-card { background: white; border-radius: 16px; overflow: hidden; border: 1px solid #e2e8f0; transition: all 0.2s; cursor: pointer; } .listing-card:hover { transform: translateY(-4px); box-shadow: 0 12px 32px rgba(0,0,0,0.1); }
.lc-img { height: 200px; display: flex; align-items: center; justify-content: center; font-size: 72px; position: relative; }
.lc-badge { position: absolute; top: 12px; left: 12px; padding: 4px 10px; border-radius: 6px; font-size: 11px; font-weight: 800; }
.badge-new { background: #22c55e; color: white; } .badge-featured { background: #ea580c; color: white; }
.lc-info { padding: 16px; }
.lc-price { font-size: 22px; font-weight: 900; color: #ea580c; margin-bottom: 6px; }
.lc-title { font-size: 15px; font-weight: 700; margin-bottom: 4px; }
.lc-location { color: #6b7280; font-size: 13px; margin-bottom: 12px; }
.lc-features { display: flex; gap: 12px; font-size: 13px; color: #6b7280; }
.stats-section { display: flex; justify-content: center; gap: 80px; padding: 48px; background: #0f172a; color: white; }
.stat { text-align: center; } .stat strong { display: block; font-size: 42px; font-weight: 900; color: #fb923c; } .stat span { color: rgba(255,255,255,0.6); font-size: 14px; }

